+import type { BaseIssue, BaseSchema } from '../../types/index.ts';
+import { pipe } from '../pipe/pipe.ts';
+import { pipeAsync } from '../pipe/pipeAsync.ts';
+
+/**
+ * Recursive placeholder schema.
+ */
+export const Recur: BaseSchema<typeof Recur, typeof Recur, never> = {
+  kind: 'schema',
+  type: 'recur',
+  reference: () => Recur,
+  expects: 'unknown',
+  async: false,
+  '~standard': undefined as never,
+  '~run'() {
+    throw new Error('Recur must be wrapped with recursive or recursiveAsync.');
+  },
+};
+
+/**
+ * Clones a value and replaces recursive placeholders.
+ */
+export function _resolveRecur<TValue>(value: TValue, recur: object): TValue {
+  if (value === Recur) {
+    return recur as TValue;
+  }
+  if (!value || typeof value !== 'object') {
+    return value;
+  }
+  if (Array.isArray(value)) {
+    return value.map((item) => _resolveRecur(item, recur)) as TValue;
+  }
+
+  const object = value as Record<PropertyKey, unknown>;
+  if (Array.isArray(object.pipe)) {
+    const resolvedPipe = _resolveRecur(object.pipe, recur) as [
+      BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+      ...unknown[],
+    ];
+    return (object.async ? pipeAsync : pipe)(...resolvedPipe) as TValue;
+  }
+
+  const clone = Object.create(Object.getPrototypeOf(value)) as Record<
+    PropertyKey,
+    unknown
+  >;
+  for (const key of Reflect.ownKeys(object)) {
+    const descriptor = Object.getOwnPropertyDescriptor(object, key);
+    if (descriptor && 'value' in descriptor) {
+      descriptor.value = _resolveRecur(descriptor.value, recur);
+    }
+    Object.defineProperty(clone, key, descriptor!);
+  }
+  return clone as TValue;
+}
